/**
 * Fleet Slice
 *
 * State management for fleet, train, depot, and route data.
 * Uses @belt/tools createSlice for reactive state.
 *
 * @see specs/006-user-interface.md Section 6.4
 */

import { createSlice, createAsyncSlice } from '@belt/tools';
import type {
  Train,
  Fleet,
  Depot,
  Route,
  TrainFilters,
  SortOptions,
  FitnessStatus,
} from '../types';

// =============================================================================
// Fleet Slice State
// =============================================================================

export interface FleetSliceState {
  fleets: Fleet[];
  trains: Train[];
  depots: Depot[];
  routes: Route[];
  selectedTrainId: string | null;
  selectedFleetId: string | null;
  filters: TrainFilters;
  sort: SortOptions;
  lastUpdated: number | null;
  [key: string]: unknown;
}

const initialFleetState: FleetSliceState = {
  fleets: [],
  trains: [],
  depots: [],
  routes: [],
  selectedTrainId: null,
  selectedFleetId: null,
  filters: {
    fleetIds: [],
    fitnessStatuses: [],
    depotIds: [],
    searchTerm: '',
  },
  sort: {
    field: 'trainNumber',
    direction: 'asc',
  },
  lastUpdated: null,
};

export const fleetSlice = createSlice({
  id: 'fleet',
  initial: initialFleetState,
  cache: { policy: 'session' },
  reducers: {
    // Fleet operations
    setFleets: (s, fleets: Fleet[]) => {
      const state = s as FleetSliceState;
      state.fleets = fleets;
      state.lastUpdated = Date.now();
    },

    // Train operations
    setTrains: (s, trains: Train[]) => {
      const state = s as FleetSliceState;
      state.trains = trains;
      state.lastUpdated = Date.now();
    },

    updateTrain: (s, train: Partial<Train> & { id: string }) => {
      const state = s as FleetSliceState;
      const index = state.trains.findIndex((t) => t.id === train.id);
      if (index !== -1) {
        state.trains[index] = { ...state.trains[index], ...train };
        state.lastUpdated = Date.now();
      }
    },

    updateTrainFitness: (
      s,
      payload: { trainId: string; status: FitnessStatus; notes?: string }
    ) => {
      const state = s as FleetSliceState;
      const train = state.trains.find((t) => t.id === payload.trainId);
      if (train) {
        train.fitnessStatus = payload.status;
        if (payload.notes !== undefined) {
          train.fitnessNotes = payload.notes;
        }
        state.lastUpdated = Date.now();
      }
    },

    updateTrainMileage: (s, payload: { trainId: string; mileageKm: number }) => {
      const state = s as FleetSliceState;
      const train = state.trains.find((t) => t.id === payload.trainId);
      if (train) {
        train.currentMileageKm = payload.mileageKm;
        state.lastUpdated = Date.now();
      }
    },

    // Depot operations
    setDepots: (s, depots: Depot[]) => {
      const state = s as FleetSliceState;
      state.depots = depots;
      state.lastUpdated = Date.now();
    },

    // Route operations
    setRoutes: (s, routes: Route[]) => {
      const state = s as FleetSliceState;
      state.routes = routes;
      state.lastUpdated = Date.now();
    },

    // Selection
    selectTrain: (s, trainId: string | null) => {
      const state = s as FleetSliceState;
      state.selectedTrainId = trainId;
    },

    selectFleet: (s, fleetId: string | null) => {
      const state = s as FleetSliceState;
      state.selectedFleetId = fleetId;
    },

    clearSelection: (s) => {
      const state = s as FleetSliceState;
      state.selectedTrainId = null;
      state.selectedFleetId = null;
    },

    // Filtering
    setFilters: (s, filters: Partial<TrainFilters>) => {
      const state = s as FleetSliceState;
      state.filters = { ...state.filters, ...filters };
    },

    setFleetFilter: (s, fleetIds: string[]) => {
      const state = s as FleetSliceState;
      state.filters.fleetIds = fleetIds;
    },

    setFitnessFilter: (s, statuses: FitnessStatus[]) => {
      const state = s as FleetSliceState;
      state.filters.fitnessStatuses = statuses;
    },

    setDepotFilter: (s, depotIds: string[]) => {
      const state = s as FleetSliceState;
      state.filters.depotIds = depotIds;
    },

    setSearchTerm: (s, term: string) => {
      const state = s as FleetSliceState;
      state.filters.searchTerm = term;
    },

    clearFilters: (s) => {
      const state = s as FleetSliceState;
      state.filters = {
        fleetIds: [],
        fitnessStatuses: [],
        depotIds: [],
        searchTerm: '',
      };
    },

    // Sorting
    setSort: (s, sort: SortOptions) => {
      const state = s as FleetSliceState;
      state.sort = sort;
    },

    toggleSortDirection: (s) => {
      const state = s as FleetSliceState;
      state.sort.direction = state.sort.direction === 'asc' ? 'desc' : 'asc';
    },

    // Bulk operations
    importFleetData: (
      s,
      payload: { fleets: Fleet[]; trains: Train[]; depots: Depot[]; routes: Route[] }
    ) => {
      const state = s as FleetSliceState;
      state.fleets = payload.fleets;
      state.trains = payload.trains;
      state.depots = payload.depots;
      state.routes = payload.routes;
      state.lastUpdated = Date.now();
    },

    // Reset
    reset: (s) => {
      const state = s as FleetSliceState;
      Object.assign(state, initialFleetState);
    },
  },
});

// =============================================================================
// Async Fleet Slice
// =============================================================================

export interface FleetApiResponse {
  fleets: Fleet[];
  trains: Train[];
  depots: Depot[];
  routes: Route[];
}

export const fleetAsyncSlice = createAsyncSlice({
  id: 'fleetApi',
  cache: {
    policy: 'public',
    ttl: '5m',
    swr: true,
  },
  context: { baseUrl: '/api/v1' },
  load: async (ctx) => {
    const baseUrl = (ctx as { baseUrl: string }).baseUrl;

    const [fleetsRes, trainsRes, depotsRes, routesRes] = await Promise.all([
      fetch(`${baseUrl}/fleets`),
      fetch(`${baseUrl}/trains?pageSize=500`),
      fetch(`${baseUrl}/depots`),
      fetch(`${baseUrl}/routes`),
    ]);

    if (!fleetsRes.ok || !trainsRes.ok || !depotsRes.ok || !routesRes.ok) {
      throw new Error('Failed to fetch fleet data');
    }

    const [fleetsData, trainsData, depotsData, routesData] = await Promise.all([
      fleetsRes.json() as Promise<{ data: Fleet[] }>,
      trainsRes.json() as Promise<{ data: Train[] }>,
      depotsRes.json() as Promise<{ data: Depot[] }>,
      routesRes.json() as Promise<{ data: Route[] }>,
    ]);

    return {
      fleets: fleetsData.data,
      trains: trainsData.data,
      depots: depotsData.data,
      routes: routesData.data,
    };
  },
});

// =============================================================================
// Selectors
// =============================================================================

export function selectFilteredTrains(state: FleetSliceState): Train[] {
  let filtered = [...state.trains];

  if (state.filters.fleetIds.length > 0) {
    filtered = filtered.filter((t) => state.filters.fleetIds.includes(t.fleetId));
  }

  if (state.filters.fitnessStatuses.length > 0) {
    filtered = filtered.filter((t) => state.filters.fitnessStatuses.includes(t.fitnessStatus));
  }

  if (state.filters.depotIds.length > 0) {
    filtered = filtered.filter(
      (t) => t.currentDepotId && state.filters.depotIds.includes(t.currentDepotId)
    );
  }

  if (state.filters.searchTerm) {
    const term = state.filters.searchTerm.toLowerCase();
    filtered = filtered.filter(
      (t) =>
        t.trainNumber.toLowerCase().includes(term) ||
        t.fleetCode.toLowerCase().includes(term) ||
        (t.fitnessNotes && t.fitnessNotes.toLowerCase().includes(term))
    );
  }

  filtered.sort((a, b) => {
    const field = state.sort.field as keyof Train;
    const aVal = a[field];
    const bVal = b[field];

    if (aVal === null || aVal === undefined) return 1;
    if (bVal === null || bVal === undefined) return -1;

    const comparison = aVal < bVal ? -1 : aVal > bVal ? 1 : 0;
    return state.sort.direction === 'asc' ? comparison : -comparison;
  });

  return filtered;
}

export function selectTrainById(state: FleetSliceState, trainId: string): Train | undefined {
  return state.trains.find((t) => t.id === trainId);
}

export function selectFleetById(state: FleetSliceState, fleetId: string): Fleet | undefined {
  return state.fleets.find((f) => f.id === fleetId);
}

export function selectDepotById(state: FleetSliceState, depotId: string): Depot | undefined {
  return state.depots.find((d) => d.id === depotId);
}

export function selectSelectedTrain(state: FleetSliceState): Train | undefined {
  return state.selectedTrainId
    ? state.trains.find((t) => t.id === state.selectedTrainId)
    : undefined;
}

export function selectTrainsByFleet(state: FleetSliceState, fleetId: string): Train[] {
  return state.trains.filter((t) => t.fleetId === fleetId);
}

export function selectFleetStats(state: FleetSliceState): {
  totalTrains: number;
  fitTrains: number;
  restrictedTrains: number;
  groundedTrains: number;
  totalMileage: number;
  avgMileage: number;
} {
  const trains = state.trains;
  const fitTrains = trains.filter((t) => t.fitnessStatus === 'FIT').length;
  const restrictedTrains = trains.filter((t) => t.fitnessStatus === 'RESTRICTED').length;
  const groundedTrains = trains.filter((t) => t.fitnessStatus === 'GROUNDED').length;
  const totalMileage = trains.reduce((sum, t) => sum + t.currentMileageKm, 0);

  return {
    totalTrains: trains.length,
    fitTrains,
    restrictedTrains,
    groundedTrains,
    totalMileage,
    avgMileage: trains.length > 0 ? Math.round(totalMileage / trains.length) : 0,
  };
}

