     1→/**
     2→ * MMS Sidebar - Train List Panel
     3→ *
     4→ * Left sidebar with train list, filters, and selection.
     5→ * Based on specs/006-user-interface.md Section 6.2.
     6→ */
     7→
     8→import {
     9→  Card,
    10→  Icon,
