    90→  const { state: canvasDataStateRaw, actions: canvasDataActions } = useCanvasData();
    91→  const { state: fleetStateRaw, actions: fleetActions } = useFleet();
    92→  const { state: pmStateRaw, actions: pmActions } = usePm();
