        <div
          ref={tooltipRef}
          style={{
            display: 'none',
            position: 'fixed',
            backgroundColor: 'white',
            border: '1px solid #e2e8f0',
            borderRadius: '6px',
            padding: '8px 12px',
            boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)',
            pointerEvents: 'none',
            zIndex: 100,
            fontSize: '12px',
            lineHeight: 1.5,
          }}
        />
      </>
    );

